import { Prisma } from "@prisma/client";
import { getSharedPrismaClient } from "@/lib/prisma";
import type { LeadPilotAIOS } from "@/lib/ai-os";
import type { ConversationEvent, TimelineCategory } from "@/lib/timeline-engine";

/**
 * Intelligence Persistence Layer (Durable / Prisma-backed).
 *
 * Replaces the previous in-memory Map store. Intelligence generated by the AI OS
 * after every assistant response is now persisted to Postgres so it survives
 * page refreshes, server restarts, HMR, multiple workers and production
 * deployments. The public API (function names + returned shapes) is unchanged
 * except that every function is now async. Nothing here changes AI behaviour —
 * it only stores what runAIOS produced.
 *
 * conversationId is the shared relationship key; we never duplicate the base
 * Conversation / Lead tables.
 */

export interface ConversationIntelligenceRecord {
  summary: string;
  visitorSummary: string;
  businessSummary: string;
  painPoints: string[];
  goals: string[];
  interests: string[];
  productsDiscussed: string[];
  objections: string[];
  positiveSignals: string[];
  negativeSignals: string[];
  nextRecommendedStep: string;
  conversationQuality: string;
  engagementScore: number;
}

export interface LeadProfileRecord {
  leadScore: number;
  qualification: string;
  scoreReasons: string[];
  completedObjectives: string[];
  pendingObjectives: string[];
  visitorStage?: string;
  currentGoal: string;
  currentStrategy: string;
  recommendedAction: string;
  currentMission: string;
  confidence: number;
}

export interface BusinessProfileRecord {
  industry?: string;
  businessType?: string;
  services?: string[];
  company?: string;
  location?: string;
  products?: string[];
  communicationStyle?: string;
  technicalLevel?: string;
}

export interface AnalyticsRecord {
  leadTrend: number[];
  qualificationHistory: string[];
  engagementHistory: number[];
  conversationQualityHistory: string[];
  goalProgressHistory: number[];
}

/** A fully assembled per-conversation bundle for aggregation/analytics. */
export interface PersistedConversation {
  conversationId: string;
  projectId?: string;
  lead?: LeadProfileRecord;
  business?: BusinessProfileRecord;
  conversation?: ConversationIntelligenceRecord;
  timeline: ConversationEvent[];
  analytics?: AnalyticsRecord;
}

function json(value: unknown): Prisma.InputJsonValue {
  return value as Prisma.InputJsonValue;
}

// --- Conversation Intelligence -------------------------------------------

export async function loadConversationIntelligence(
  conversationId: string
): Promise<ConversationIntelligenceRecord | null> {
  const prisma = getSharedPrismaClient();
  const row = await prisma.conversationIntelligence.findUnique({ where: { conversationId } });
  return row ? (row.data as unknown as ConversationIntelligenceRecord) : null;
}

export async function saveConversationIntelligence(
  conversationId: string,
  record: ConversationIntelligenceRecord,
  projectId?: string
): Promise<void> {
  const prisma = getSharedPrismaClient();
  await prisma.conversationIntelligence.upsert({
    where: { conversationId },
    create: { conversationId, projectId: projectId ?? null, data: json(record) },
    update: { data: json(record), projectId: projectId ? projectId : undefined }
  });
}

export async function updateConversationIntelligence(
  conversationId: string,
  partial: Partial<ConversationIntelligenceRecord>
): Promise<void> {
  const existing = await loadConversationIntelligence(conversationId);
  const next: ConversationIntelligenceRecord = {
    ...(existing ?? ({} as ConversationIntelligenceRecord)),
    ...partial
  };
  await saveConversationIntelligence(conversationId, next);
}

